import { sortParsedCells, parsePathSuffix } from '@/utils/DiskDirStripCanvasRenderer.js'

const MAP_NAME_RE = /^([a-zA-Z]{0,2})_(\d+)_(\d+)\.([a-zA-Z0-9]+)$/i
const MAP_PUBLIC_BASE = '/images/map'

/** 磁盘文件名 m_x_y -> 渲染器用 m_y_x（imageX/imageY 与文件名第二、三段对调） */
export function swapXYInFileName (fileName) {
  const m = String(fileName || '').match(MAP_NAME_RE)
  if (!m) return fileName
  return `${m[1]}_${m[3]}_${m[2]}.${m[4]}`
}

/** 仅读取文件名，不调用 context(id) 避免 webpack 内联图片 */
const mapFileContext = require.context('@/assets/images/map', false, /\.(jpe?g|png|gif|bmp|webp)$/i)
const MAP_ACTUAL_NAMES = mapFileContext.keys().map((key) => key.replace(/^\.\//, ''))

const virtualToActualName = Object.create(null)
MAP_ACTUAL_NAMES.forEach((actualName) => {
  virtualToActualName[swapXYInFileName(actualName)] = actualName
})

export function getMapFileList () {
  return Object.keys(virtualToActualName).slice().sort((a, b) =>
    a.localeCompare(b, undefined, { numeric: true })
  )
}

/**
 * @param {string} virtualName
 * @param {string|number} [cacheBust] 传入后强制走网络（IMG 对比用）
 */
export function buildMapImageUrl (virtualName, cacheBust) {
  const name = String(virtualName || '').replace(/\\/g, '/').split('/').pop()
  const actualName = virtualToActualName[name] || name
  const base = `${MAP_PUBLIC_BASE}/${actualName}`
  if (cacheBust == null || cacheBust === '') return base
  return `${base}?_=${encodeURIComponent(String(cacheBust))}`
}

export function getSortedMapCells (cacheBust) {
  const parsed = getMapFileList()
    .map((virtualName) => {
      const info = parsePathSuffix(virtualName)
      if (!info) return null
      return {
        ...info,
        virtualName,
        actualName: virtualToActualName[virtualName],
        url: buildMapImageUrl(virtualName, cacheBust)
      }
    })
    .filter(Boolean)
  return sortParsedCells(parsed)
}

export function groupCellsByRow (cells) {
  const rowMap = new Map()
  cells.forEach((cell) => {
    if (!rowMap.has(cell.imageY)) rowMap.set(cell.imageY, [])
    rowMap.get(cell.imageY).push(cell)
  })
  return [...rowMap.entries()]
    .sort((a, b) => a[0] - b[0])
    .map(([imageY, rowCells]) => ({
      imageY,
      cells: rowCells.sort((a, b) => {
        const orderA = (a.surface || '').charCodeAt(0) * 10000 + a.imageX
        const orderB = (b.surface || '').charCodeAt(0) * 10000 + b.imageX
        return orderA - orderB
      })
    }))
}

export function getMapImageCount () {
  return getMapFileList().length
}
