/**
 * 条带 Canvas 放大镜
 * - 绝不从主 canvas 裁剪，每张图独立 new Image() 按路径加载
 * - 根据放大镜宽高 + 命中图锚点，动态计算需覆盖视口的图片范围（非固定九宫格）
 */

const DEFAULT_LOUPE_W = 640
const DEFAULT_LOUPE_H = 640

function cellColKey (cell) {
  if (!cell) return ''
  return `${cell.surface}_${cell.imageX}`
}

function cellGridKey (cell) {
  if (!cell) return ''
  return `${cell.surface}_${cell.imageX}_${cell.imageY}`
}

function toAbsoluteUrl (url) {
  const s = String(url || '').trim()
  if (!s || /^https?:\/\//i.test(s)) return s
  try {
    const path = s.startsWith('/') ? s : `/${s}`
    if (typeof location !== 'undefined') return new URL(path, location.origin).href
  } catch (_) {}
  return s
}

function appendCacheBust (url, token) {
  if (!token) return url
  const sep = url.includes('?') ? '&' : '?'
  return `${url}${sep}_loupe=${encodeURIComponent(String(token))}`
}

/** 解析单元格对应的图片 URL（优先 url，其次 path + buildImageUrl） */
function resolveCellImageUrl (cell, renderer) {
  if (!cell) return ''
  if (cell.url) return String(cell.url)
  const path = cell.path || cell.fileName
  if (path && renderer && typeof renderer.buildImageUrl === 'function') {
    return renderer.buildImageUrl(path)
  }
  return ''
}

/**
 * 命中图锚点为 (hitDraw, hitDraw)，偏移 n 的格绘制于 hitDraw + n * tileSize
 * 求与视口 [0, loupeSize) 相交的 offset 范围
 */
function calcTileOffsetRange (hitDraw, tileSize, loupeSize) {
  const tile = Math.max(1, tileSize)
  const minOffset = Math.ceil((-hitDraw - tile + 1) / tile)
  const maxOffset = Math.floor((loupeSize - hitDraw - 1) / tile)
  return { min: minOffset, max: maxOffset }
}

/** 按视口动态取需要绘制的格子 */
function buildVisibleGrid (hitCell, parsed, renderer, hitDrawX, hitDrawY, tileW, tileH, loupeW, loupeH) {
  const map = Object.create(null)
  ;(parsed || []).forEach((cell) => {
    map[cellGridKey(cell)] = cell
  })

  const colRange = calcTileOffsetRange(hitDrawX, tileW, loupeW)
  const rowRange = calcTileOffsetRange(hitDrawY, tileH, loupeH)
  const list = []
  const hitX = hitCell.imageX
  const hitY = hitCell.imageY
  const surface = hitCell.surface

  for (let rowOffset = rowRange.min; rowOffset <= rowRange.max; rowOffset++) {
    for (let colOffset = colRange.min; colOffset <= colRange.max; colOffset++) {
      const cell = map[`${surface}_${hitX + colOffset}_${hitY + rowOffset}`]
      if (!cell) continue
      const url = resolveCellImageUrl(cell, renderer)
      if (!url) continue
      list.push({ cell, url, colOffset, rowOffset })
    }
  }
  return list
}

/** 命中检测 */
export function hitTestStripAtPoint (renderer, clientX, clientY) {
  const state = renderer && renderer._lastRenderState
  if (!state || !state.layout || !state.sortedParsed) return null

  for (const { canvas, plan } of state.screenCanvases || []) {
    if (!canvas || !plan) continue

    const rect = canvas.getBoundingClientRect()
    if (
      clientX < rect.left || clientX > rect.right ||
      clientY < rect.top || clientY > rect.bottom
    ) continue

    const offsetX = (clientX - rect.left) * (canvas.width / Math.max(1, rect.width))
    const offsetY = (clientY - rect.top) * (canvas.height / Math.max(1, rect.height))
    const hit = hitTestCellInPlan(state.sortedParsed, state.layout, plan, offsetX, offsetY, renderer)
    if (hit) return { ...hit, clientX, clientY, canvas, plan }
  }
  return null
}

function hitTestCellInPlan (parsed, layout, plan, offsetX, offsetY, renderer) {
  const { yFirst, yLast } = plan
  const { canvasColW, canvasXOff, rowDrawH, canvasSurfaceBaseLeft, imageHeight } = layout
  const yOffset = (yFirst - 1) * rowDrawH

  for (let i = parsed.length - 1; i >= 0; i--) {
    const cell = parsed[i]
    if (cell.imageY < yFirst || cell.imageY > yLast) continue

    const key = cellColKey(cell)
    const left = Math.round((canvasSurfaceBaseLeft[cell.surface] || 0) + (canvasXOff[key] || 0))
    const top = (cell.imageY - 1) * rowDrawH - yOffset
    const width = canvasColW[key] || 1
    const height = rowDrawH

    if (offsetX >= left && offsetX < left + width && offsetY >= top && offsetY < top + height) {
      const naturalW = renderer._getCellNaturalWidth(cell)
      const naturalH = imageHeight
      const mouseInImageX = (offsetX - left) * (naturalW / Math.max(1, width))
      const mouseInImageY = (offsetY - top) * (naturalH / Math.max(1, height))
      return { cell, mouseInImageX, mouseInImageY, naturalW, naturalH }
    }
  }
  return null
}

/** 每次独立 new Image 加载，不走主 canvas */
function loadLoupeImage (url, cacheToken) {
  const absUrl = appendCacheBust(toAbsoluteUrl(url), cacheToken)
  if (!absUrl) return Promise.resolve(null)

  return new Promise((resolve) => {
    const img = new Image()
    img.onload = () => resolve(img.naturalWidth > 0 ? img : null)
    img.onerror = () => resolve(null)
    img.src = absUrl
  })
}

export default class DiskStripLoupe {
  constructor (options = {}) {
    this.canvas = options.canvas || null
    this.panel = options.panel || null
    this.width = options.width || DEFAULT_LOUPE_W
    this.height = options.height || DEFAULT_LOUPE_H
    this.onOpenChange = typeof options.onOpenChange === 'function' ? options.onOpenChange : null
    this.open = false
    this._loupeSession = 0
    this._rafId = null
    this._updateSeq = 0
    this._boundContextMenu = this._handleContextMenu.bind(this)
    this._boundMouseMove = this._handleMouseMove.bind(this)
    this._renderer = null
  }

  attach (renderer) {
    this.detach()
    this._renderer = renderer
    const container = renderer && renderer.container
    if (!container) return
    container.addEventListener('contextmenu', this._boundContextMenu)
    container.addEventListener('mousemove', this._boundMouseMove, { passive: true })
  }

  detach () {
    const container = this._renderer && this._renderer.container
    if (container) {
      container.removeEventListener('contextmenu', this._boundContextMenu)
      container.removeEventListener('mousemove', this._boundMouseMove)
    }
    if (this._rafId) {
      cancelAnimationFrame(this._rafId)
      this._rafId = null
    }
    this._renderer = null
  }

  destroy () {
    this.setOpen(false)
    this.detach()
  }

  setOpen (open) {
    const next = !!open
    if (next && !this.open) {
      // 每次打开放大镜换一批 cache token，Network 里能看到 img 请求
      this._loupeSession = Date.now()
    }
    this.open = next
    if (this.panel) this.panel.style.display = this.open ? 'block' : 'none'
    if (this.onOpenChange) this.onOpenChange(this.open)
    if (!this.open && this.canvas) {
      const ctx = this.canvas.getContext('2d')
      if (ctx) ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)
    }
  }

  toggle (event) {
    this.setOpen(!this.open)
    if (this.open && event) this.update(event)
  }

  _handleContextMenu (event) {
    event.preventDefault()
    this.toggle(event)
  }

  _handleMouseMove (event) {
    if (!this.open || this._rafId) return
    this._rafId = requestAnimationFrame(() => {
      this._rafId = null
      this.update(event)
    })
  }

  _positionPanel (clientX, clientY) {
    if (!this.panel) return
    const pad = 16
    const w = this.width
    const h = this.panel.offsetHeight || this.height + 36
    let left = clientX + pad
    let top = clientY + pad
    if (typeof window !== 'undefined') {
      if (left + w > window.innerWidth - pad) left = clientX - w - pad
      if (top + h > window.innerHeight - pad) top = clientY - h - pad
      left = Math.max(pad, left)
      top = Math.max(pad, top)
    }
    this.panel.style.left = `${left}px`
    this.panel.style.top = `${top}px`
  }

  async update (event) {
    if (!this.open || !this._renderer || !this.canvas) return

    const hit = hitTestStripAtPoint(this._renderer, event.clientX, event.clientY)
    if (!hit) return

    this._positionPanel(event.clientX, event.clientY)

    const state = this._renderer._lastRenderState
    const loupeW = this.width
    const loupeH = this.height
    const updateSeq = ++this._updateSeq

    if (this.canvas.width !== loupeW) this.canvas.width = loupeW
    if (this.canvas.height !== loupeH) this.canvas.height = loupeH

    const ctx = this.canvas.getContext('2d')
    if (!ctx) return

    const hitCell = hit.cell
    const hitDrawX = Math.floor(loupeW / 2 - hit.mouseInImageX)
    const hitDrawY = Math.floor(loupeH / 2 - hit.mouseInImageY)
    const tileW = Math.max(1, hit.naturalW || 1)
    const tileH = Math.max(1, hit.naturalH || 1)

    const visibleGrid = buildVisibleGrid(
      hitCell,
      state.sortedParsed,
      this._renderer,
      hitDrawX,
      hitDrawY,
      tileW,
      tileH,
      loupeW,
      loupeH
    )

    const loaded = await Promise.all(
      visibleGrid.map(({ cell, url, colOffset, rowOffset }) => {
        const token = `${this._loupeSession}_${cellGridKey(cell)}`
        return loadLoupeImage(url, token).then((img) => ({ cell, url, img, colOffset, rowOffset }))
      })
    )
    if (updateSeq !== this._updateSeq) return

    ctx.fillStyle = '#000'
    ctx.fillRect(0, 0, loupeW, loupeH)

    loaded.forEach(({ img, colOffset, rowOffset }) => {
      if (!img) return
      const drawX = hitDrawX + colOffset * tileW
      const drawY = hitDrawY + rowOffset * tileH
      ctx.drawImage(img, drawX, drawY, img.naturalWidth, img.naturalHeight)
    })

    ctx.strokeStyle = 'rgba(0, 255, 0, 0.85)'
    ctx.lineWidth = 1
    ctx.beginPath()
    ctx.moveTo(loupeW / 2, 0)
    ctx.lineTo(loupeW / 2, loupeH)
    ctx.moveTo(0, loupeH / 2)
    ctx.lineTo(loupeW, loupeH / 2)
    ctx.stroke()
  }
}
