<template>
  <div class="tile-panel tile-canvas-panel">
    <el-card shadow="never" class="perf-card" v-if="perfSummary">
      <div slot="header" class="perf-header">Canvas 性能指标</div>
      <el-row :gutter="12">
        <el-col :span="6">
          <div class="perf-item">
            <div class="perf-label">网络请求总耗时</div>
            <div class="perf-value">{{ formatMs(perfSummary.networkTotalMs) }}</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="perf-item">
            <div class="perf-label">含解码墙钟</div>
            <div class="perf-value">{{ formatMs(perfSummary.fetchAndDecodeWallMs) }}</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="perf-item">
            <div class="perf-label">全部渲染完成</div>
            <div class="perf-value">{{ formatMs(perfSummary.renderCompleteTotalMs) }}</div>
          </div>
        </el-col>
        <el-col :span="6">
          <div class="perf-item">
            <div class="perf-label">canvas 数量</div>
            <div class="perf-value">{{ perfSummary.canvasCount != null ? perfSummary.canvasCount : '-' }}</div>
          </div>
        </el-col>
      </el-row>
    </el-card>

    <div
      class="tile-viewport"
      v-loading="stripCanvasLoading"
      element-loading-background="rgba(0, 0, 0, 1)"
      element-loading-spinner="spinner"
      element-loading-custom-class="custom_strip_canvas_loading"
    >
      <div ref="canvasRenderBox" class="canvas_render_box">
        <div ref="canvasRenderBoxInner" class="canvas_render_box_inner"></div>
      </div>
    </div>

    <div
      ref="loupePanel"
      class="disk-strip-loupe-panel"
      :class="{ 'is-open': loupeOpen }"
    >
      <div class="disk-strip-loupe-header">
        <span>放大镜</span>
        <span class="disk-strip-loupe-tip">右键开关 · 移动鼠标更新</span>
      </div>
      <canvas ref="loupeCanvas" class="disk-strip-loupe-canvas" width="640" height="640"></canvas>
    </div>
  </div>
</template>

<script>
import DiskDirStripCanvasRenderer from '@/utils/DiskDirStripCanvasRenderer.js'
import DiskStripLoupe from '@/utils/DiskStripLoupe.js'
import { getMapFileList, buildMapImageUrl } from '@/utils/mapImageAssets.js'

export default {
  name: 'TileCanvasPanel',
  data () {
    return {
      stripRenderer: null,
      stripLoupe: null,
      loupeOpen: false,
      stripCanvasLoading: false,
      filesDataList: getMapFileList(),
      perfSummary: null
    }
  },
  mounted () {
    this.$nextTick(() => {
      this.initLoupe()
      this.initStripRenderer()
      this.renderStripImages()
    })
  },
  beforeDestroy () {
    if (this.stripRenderer) {
      this.stripRenderer.destroy()
      this.stripRenderer = null
    }
    if (this.stripLoupe) {
      this.stripLoupe.destroy()
      this.stripLoupe = null
    }
  },
  methods: {
    formatMs (ms) {
      if (ms == null || !Number.isFinite(ms)) return '-'
      return `${ms.toFixed(2)} ms（${(ms / 1000).toFixed(2)} s）`
    },

    initLoupe () {
      if (this.stripLoupe || !this.$refs.loupeCanvas) return
      this.stripLoupe = new DiskStripLoupe({
        canvas: this.$refs.loupeCanvas,
        panel: this.$refs.loupePanel,
        width: 640,
        height: 640,
        onOpenChange: (open) => {
          this.loupeOpen = open
        }
      })
    },

    initStripRenderer () {
      const box = this.$refs.canvasRenderBox
      const inner = this.$refs.canvasRenderBoxInner
      if (!box || !inner || this.stripRenderer) return

      this.initLoupe()

      this.stripRenderer = new DiskDirStripCanvasRenderer({
        container: box,
        inner,
        buildImageUrl: (path) => {
          const virtualName = String(path || '').replace(/\\/g, '/').split('/').pop()
          return buildMapImageUrl(virtualName)
        }
      })

      if (this.stripLoupe) {
        this.stripRenderer.bindLoupe(this.stripLoupe)
      }
    },

    renderStripImages () {
      if (!this.filesDataList.length) {
        this.stripRenderer && this.stripRenderer.clearRenderCache()
        return
      }

      if (!this.stripRenderer) {
        this.initStripRenderer()
      }
      if (!this.stripRenderer) return

      const box = this.$refs.canvasRenderBox
      const viewBoxWidth = box ? box.clientWidth : 800
      this.stripCanvasLoading = true
      this.perfSummary = null

      this.stripRenderer
        .render(
          {
            filesDataList: this.filesDataList,
            imagePrePath: '',
            viewBoxWidth
          },
          {
            onFirstScreen: () => {
              this.stripCanvasLoading = false
            },
            onComplete: () => {
              this.stripCanvasLoading = false
              if (this.stripRenderer && this.stripLoupe) {
                this.stripRenderer.bindLoupe(this.stripLoupe)
              }
            },
            onTiming: (timing) => {
              this.perfSummary = timing
              console.log('[TileCanvasPanel] perf', timing)
            }
          }
        )
        .catch((e) => {
          console.error('[TileCanvasPanel] render', e)
          this.stripCanvasLoading = false
        })
    },

    reload () {
      this.filesDataList = getMapFileList()
      this.renderStripImages()
    }
  }
}
</script>

<style scoped>
.tile-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
}

.tile-viewport {
  position: relative;
  flex: 1;
  min-height: 360px;
  border: 1px solid #dcdfe6;
  border-radius: 4px;
  overflow: hidden;
}

.perf-card {
  margin-bottom: 12px;
}

.perf-card >>> .el-card__header {
  padding: 10px 16px;
}

.perf-card >>> .el-card__body {
  padding: 12px 16px;
}

.perf-header {
  font-weight: 600;
}

.perf-item {
  text-align: center;
  padding: 10px;
  background: #f5f7fa;
  border-radius: 4px;
}

.perf-label {
  color: #909399;
  font-size: 13px;
  margin-bottom: 6px;
}

.perf-value {
  color: #303133;
  font-size: 15px;
  font-weight: 600;
}
</style>

<style>
.disk-strip-loupe-panel {
  display: none;
  position: fixed;
  z-index: 10000;
  background: #1a1a1a;
  border: 1px solid #409eff;
  border-radius: 6px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.45);
  pointer-events: none;
  overflow: hidden;
}

.disk-strip-loupe-panel.is-open {
  display: block;
}

.disk-strip-loupe-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 10px;
  background: #303133;
  color: #fff;
  font-size: 13px;
}

.disk-strip-loupe-tip {
  color: #909399;
  font-size: 12px;
}

.disk-strip-loupe-canvas {
  display: block;
  vertical-align: top;
  background: #000;
}
</style>
