/**
 * 列宽：new Image；绘制：主线程 fetch（绝对 URL）+ createImageBitmap，带并发上限。
 * 说明：Blob Worker 内 fetch 在部分环境（CSP / blob 源解析）下不发起请求或永不回调，会导致整屏 Promise 挂死、画布空白。
 */

const B_IMAGE_RE = /([A-Z]{0,2})_(\d+)_(\d+)\.([a-zA-Z0-9]+)$/i;

/** 相对路径转为页面绝对地址，保证 fetch 与 <img> 同源行为一致 */
function toAbsoluteImageUrl(url) {
  const s = String(url || '').trim();
  if (!s) return s;
  if (/^https?:\/\//i.test(s) || s.startsWith('blob:') || s.startsWith('data:')) return s;
  try {
    const path = s.startsWith('/') ? s : `/${s}`;
    if (typeof location !== 'undefined' && location.href) {
      return new URL(path, location.origin).href;
    }
  } catch (_) {}
  return s;
}

/**
 * 主线程并发拉图 + 解码（Network 里为 fetch，与 Worker 内 fetch 不同）
 */
const StripImageLoader = {
  maxConcurrent: 8,
  inflight: 0,
  queue: [],
  seq: 0,
  waiters: new Map(),

  /**
   * @param {string} url
   * @param {number} maxConcurrent
   * @param {{
   *   onFetchStart?: () => void,
   *   onNetworkBytesReady?: () => void
   * }} [lifecycle]
   * - onFetchStart：即将发起 fetch 前（每任务一次）
   * - onNetworkBytesReady：fetch 成功且 arrayBuffer 读完、尚未 createImageBitmap 解码前（每任务一次）
   */
  loadBitmap(url, maxConcurrent, lifecycle) {
    const mc = Math.max(1, maxConcurrent || 8);
    this.maxConcurrent = mc;
    return new Promise((resolve, reject) => {
      const id = ++this.seq;
      const abs = toAbsoluteImageUrl(url);
      this.waiters.set(id, { resolve, reject });
      this.queue.push({ id, url: abs, lifecycle });
      this._pump();
    });
  },

  _pump() {
    while (this.inflight < this.maxConcurrent && this.queue.length) {
      const { id, url, lifecycle } = this.queue.shift();
      this.inflight++;
      (async () => {
        try {
          if (lifecycle && typeof lifecycle.onFetchStart === 'function') {
            try {
              lifecycle.onFetchStart();
            } catch (_) {}
          }
          const res = await fetch(url, { credentials: 'same-origin', mode: 'cors' });
          if (!res.ok) throw new Error(`HTTP ${res.status}`);
          const ab = await res.arrayBuffer();
          if (!ab || !ab.byteLength) throw new Error('empty body');
          if (lifecycle && typeof lifecycle.onNetworkBytesReady === 'function') {
            try {
              lifecycle.onNetworkBytesReady();
            } catch (_) {}
          }
          const bmp = await createImageBitmap(new Blob([ab]));
          const w = this.waiters.get(id);
          if (w) {
            w.resolve(bmp);
            this.waiters.delete(id);
          } else {
            try {
              bmp.close();
            } catch (_) {}
          }
        } catch (e) {
          const w = this.waiters.get(id);
          if (w) {
            w.reject(e);
            this.waiters.delete(id);
          }
        } finally {
          this.inflight--;
          this._pump();
        }
      })();
    }
  },
};
/** 全局列宽（等宽模式或布局用每列最大宽）：`${surface}_${imageX}` -> naturalWidth */
const GLOBAL_COL_WIDTH_BY_IMAGE_X = Object.create(null);
/** 列内不等宽：按单元格缓存 naturalWidth，key 为 url 或 surface_imageX_imageY */
const GLOBAL_CELL_WIDTH_BY_KEY = Object.create(null);
/** 全局行高（像素），首次 new Image 得到后沿用 */
let GLOBAL_ROW_IMAGE_HEIGHT = 0;

function surfaceCharCode(surface) {
  const s = String(surface ?? '');
  return s.length > 0 ? s.charCodeAt(0) : 0;
}

/** 列宽缓存与布局列 key：surface + imageX */
function colCacheKey(surface, imageX) {
  return `${surface}_${imageX}`;
}

function cellColKey(cell) {
  if (!cell) return '';
  return colCacheKey(cell.surface, cell.imageX);
}

/** 取宽与布局前排序：先 imageY，再 charCode*10000+imageX */
export function sortParsedCells(parsed) {
  const list = Array.isArray(parsed) ? parsed : [];
  return [...list].sort((a, b) => {
    if (a.imageY !== b.imageY) return a.imageY - b.imageY;
    const orderA = surfaceCharCode(a.surface) * 10000 + a.imageX;
    const orderB = surfaceCharCode(b.surface) * 10000 + b.imageX;
    return orderA - orderB;
  });
}

/** 按排序后首次出现顺序得到列 key 列表 */
function buildOrderedColumnKeys(parsed) {
  const keys = [];
  const seen = new Set();
  for (const cell of parsed) {
    const key = cellColKey(cell);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    keys.push(key);
  }
  return keys;
}

function cellWidthCacheKey(cell) {
  if (!cell) return '';
  const url = String(cell.url || '').trim();
  if (url) return url;
  return `${cell.surface}_${cell.imageX}_${cell.imageY}`;
}

/**
 * 各 surface 条带在画布上的起始 X（原始像素）。
 * baseLeft：相对 baseSurface 条带右缘的绝对间距；
 * baseSurface：累加这些 surface 全部列宽后，再叠加 baseLeft，作为当前 surface 条带的起点。
 * 未出现在 emendBaseLeftInfo 中的 surface 起点为 0。
 *
 * @param {string[]} columnKeys
 * @param {Record<string, number>} colWidths
 * @param {Record<string, { surface: string, imageX: number }>} colMeta
 * @param {Record<string, { baseLeft?: number, baseSurface?: string[] }>|null|undefined} emendBaseLeftInfo
 */
function computeSurfaceBaseLeft(columnKeys, colWidths, colMeta, emendBaseLeftInfo) {
  const widthSumBySurface = Object.create(null);
  for (const key of columnKeys) {
    const meta = colMeta[key];
    if (!meta) continue;
    const surface = meta.surface;
    const w = colWidths[key] || 0;
    widthSumBySurface[surface] = (widthSumBySurface[surface] || 0) + w;
  }
  const baseLeftBySurface = Object.create(null);
  if (!emendBaseLeftInfo || typeof emendBaseLeftInfo !== 'object') {
    return baseLeftBySurface;
  }
  for (const surfaceKey of Object.keys(emendBaseLeftInfo)) {
    const cfg = emendBaseLeftInfo[surfaceKey];
    if (!cfg) continue;
    const baseLeft = Number(cfg.baseLeft) || 0;
    const baseSurfaces = Array.isArray(cfg.baseSurface) ? cfg.baseSurface : [];
    let sum = 0;
    for (const baseSurface of baseSurfaces) {
      sum += widthSumBySurface[baseSurface] || 0;
    }
    baseLeftBySurface[surfaceKey] = baseLeft + sum;
  }
  return baseLeftBySurface;
}
let DISK_STRIP_GLOBAL_TASK_ID = null;
let DISK_STRIP_TASK_COUNTER = 0;

function generateDiskStripTaskId() {
  DISK_STRIP_TASK_COUNTER += 1;
  return `disk_strip_task_${Date.now()}_${DISK_STRIP_TASK_COUNTER}`;
}

function parsePathSuffix(pathOrName) {
  const base = String(pathOrName || '')
    .replace(/\\/g, '/')
    .split('/')
    .pop()
    .trim();
  const m = base.match(B_IMAGE_RE);
  if (!m) {
    console.warn(`图片路径结尾不符合预期: ${pathOrName} , 期望结尾是 检测面_x坐标_y坐标.格式`);
    return null;
  };
  return {
    fileName: base,
    surface: m[1] || '',
    imageX: parseInt(m[2], 10),
    imageY: parseInt(m[3], 10),
    ext: m[4],
  };
}

export function buildDiskFileDataPath(storageBasePath, pathOfFilesDataList, fileName) {
  const i = Math.max(0, String(storageBasePath || '').length - 1);
  const pre = String(pathOfFilesDataList || '').replace(/\\/g, '/').slice(i);
  const f = String(fileName || '').replace(/^[/\\]+/, '');
  if (!pre) return f;
  return pre.endsWith('/') ? pre + f : pre + '/' + f;
}

/** new Image 取 naturalWidth / naturalHeight */
function loadImageNatural(url) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const w = img.naturalWidth || 1;
      const h = img.naturalHeight || 1;
      if (w < 1 || h < 1) {
        reject(new Error('natural size invalid'));
        return;
      }
      resolve({ width: w, height: h, img });
    };
    img.onerror = () => reject(new Error('Image load failed: ' + url));
    img.src = url;
  });
}

export function clearDiskStripGlobalColumnCache() {
  Object.keys(GLOBAL_COL_WIDTH_BY_IMAGE_X).forEach((k) => {
    delete GLOBAL_COL_WIDTH_BY_IMAGE_X[k];
  });
  Object.keys(GLOBAL_CELL_WIDTH_BY_KEY).forEach((k) => {
    delete GLOBAL_CELL_WIDTH_BY_KEY[k];
  });
  GLOBAL_ROW_IMAGE_HEIGHT = 0;
}

/**
 * 由 strip 渲染过程采集的原始时刻与派生耗时（单位 ms，与 performance.now() 同源）
 */
function buildStripTimingResult(st) {
  if (!st || st.firstFetchStart == null) return null;
  const t1 = st.firstFetchStart;
  const tNet = st.lastNetworkEnd;
  const t2 = st.lastFetchEnd;
  const t3 = st.allPaintedAt;
  return {
    firstFetchStartMs: t1,
    lastNetworkEndMs: tNet,
    lastFetchEndMs: t2,
    allPaintedMs: t3,
    /**
     * 从首次即将 fetch 到最后一格「HTTP 响应体读完」（含 fetch + arrayBuffer，不含 createImageBitmap 解码）
     */
    networkTotalMs: tNet != null ? tNet - t1 : null,
    /**
     * 从首次即将 fetch 到最后一格 createImageBitmap 完成（含解码，墙钟重叠下的完成时刻）
     */
    fetchAndDecodeWallMs: t2 != null ? t2 - t1 : null,
    /** 从首次 fetch 发起到全部离屏绘制并入 DOM 且双 rAF 后（近似已上屏） */
    renderCompleteTotalMs: t3 != null ? t3 - t1 : null,
    /** 末次解码完成到双 rAF：绘制与合成间隙 */
    afterLastFetchMs: t2 != null && t3 != null ? t3 - t2 : null,
    /** 有效解析后的待绘制图片数 */
    totalImages: st.totalImages != null ? st.totalImages : null,
    /** 实际创建的离屏/主 canvas 数量（分屏数） */
    canvasCount: st.canvasCount != null ? st.canvasCount : null,
  };
}

export default class DiskDirStripCanvasRenderer {
  constructor(options) {
    if (!options || !options.container || !options.inner || typeof options.buildImageUrl !== 'function') {
      throw new Error('DiskDirStripCanvasRenderer: container、inner、buildImageUrl 必填');
    }
    this.container = options.container;
    this.inner = options.inner;
    this.buildImageUrl = options.buildImageUrl;
    /** Decode Worker 池大小 */
    this.workerCount = options.workerCount ?? Math.min(4, typeof navigator !== 'undefined' ? navigator.hardwareConcurrency || 4 : 4);
    /** 独立 Fetch Worker 内最大并发请求数（同 DrawMulitiImgToCanvas） */
    this.maxConcurrentFetch = options.maxConcurrentFetch ?? 8;
    /**
     * 同 surface+imageX 列内图片宽度是否一致。
     * false（默认）：每格单独 new Image 取宽并缓存，布局列宽取该列最大值。
     * true：每列只采样一张图宽度，整列共用。
     */
    this.uniformColumnWidth = options.uniformColumnWidth === true;
    this._resizeObs = null;
    this._destroyed = false;
    this._renderToken = 0;
    this._currentTaskId = null;
    /** 上次 render / renderIncremental 成功后的状态，用于同板追加图片 */
    this._lastRenderState = null;
    /** verticalLine hover tooltip 元素（按需创建） */
    this._verticalLineTooltipEl = null;
    /** 鼠标十字线覆盖层（按需创建） */
    this._mouseCrosshairHorizontalEl = null;
    this._mouseCrosshairVerticalEl = null;
    /** 放大镜（右键开关） */
    this._loupe = null;
    if (options.loupe && options.loupe.canvas) {
      this._loupe = options.loupe.instance || null;
    }
  }

  /** 绑定放大镜（render 完成后调用） */
  bindLoupe (loupeInstance) {
    if (this._loupe && this._loupe !== loupeInstance) {
      this._loupe.detach();
    }
    this._loupe = loupeInstance || null;
    if (this._loupe) {
      this._loupe.attach(this);
    }
  }

  static invalidateGlobalTask() {
    const newTaskId = generateDiskStripTaskId();
    DISK_STRIP_GLOBAL_TASK_ID = newTaskId;
    return newTaskId;
  }

  _beginNewTask() {
    const taskId = DiskDirStripCanvasRenderer.invalidateGlobalTask();
    this._currentTaskId = taskId;
    return taskId;
  }

  _isTaskValid(taskId) {
    return !!taskId && taskId === this._currentTaskId && taskId === DISK_STRIP_GLOBAL_TASK_ID;
  }

  _ensureVerticalLineTooltip() {
    if (this._verticalLineTooltipEl && this._verticalLineTooltipEl.parentNode) return this._verticalLineTooltipEl;
    if (!this.container) return null;
    const el = document.createElement('div');
    el.style.position = 'absolute';
    el.style.zIndex = '9999';
    el.style.pointerEvents = 'none';
    el.style.padding = '2px 8px';
    el.style.borderRadius = '4px';
    el.style.fontSize = '32px';
    el.style.lineHeight = '1.4';
    el.style.color = '#fff';
    el.style.background = 'rgba(0, 0, 0, 0.85)';
    el.style.whiteSpace = 'nowrap';
    el.style.display = 'none';
    this.container.appendChild(el);
    this._verticalLineTooltipEl = el;
    return el;
  }

  _hideVerticalLineTooltip() {
    if (this._verticalLineTooltipEl) {
      this._verticalLineTooltipEl.style.display = 'none';
    }
  }

  _ensureMouseCrosshairElements() {
    if (!this.container) return null;
    if (
      this._mouseCrosshairHorizontalEl &&
      this._mouseCrosshairHorizontalEl.parentNode &&
      this._mouseCrosshairVerticalEl &&
      this._mouseCrosshairVerticalEl.parentNode
    ) {
      return {
        horizontal: this._mouseCrosshairHorizontalEl,
        vertical: this._mouseCrosshairVerticalEl,
      };
    }
    const makeLine = () => {
      const line = document.createElement('div');
      line.style.position = 'absolute';
      line.style.zIndex = '9998';
      line.style.pointerEvents = 'none';
      line.style.background = '#80f380';
      line.style.display = 'none';
      this.container.appendChild(line);
      return line;
    };
    this._mouseCrosshairHorizontalEl = makeLine();
    this._mouseCrosshairVerticalEl = makeLine();
    return {
      horizontal: this._mouseCrosshairHorizontalEl,
      vertical: this._mouseCrosshairVerticalEl,
    };
  }

  _updateMouseCrosshair(canvas, ev) {
    const lines = this._ensureMouseCrosshairElements();
    if (!lines || !canvas || !this.container) return;
    const cRect = this.container.getBoundingClientRect();
    const rect = canvas.getBoundingClientRect();
    const xInCanvas = ev.clientX - rect.left;
    const yInCanvas = ev.clientY - rect.top;
    if (xInCanvas < 0 || yInCanvas < 0 || xInCanvas > rect.width || yInCanvas > rect.height) {
      this._hideMouseCrosshair();
      return;
    }
    const canvasLeft = rect.left - cRect.left;
    const xInContainer = ev.clientX - cRect.left;
    const yInContainer = ev.clientY - cRect.top;

    const h = lines.horizontal;
    h.style.left = `${canvasLeft}px`;
    h.style.top = `${yInContainer}px`;
    h.style.width = `${rect.width}px`;
    h.style.height = '1px';
    h.style.transform = 'translateY(-0.5px)';
    h.style.display = 'block';

    const v = lines.vertical;
    v.style.left = `${xInContainer}px`;
    v.style.top = `0`;
    v.style.bottom = `0`;
    v.style.width = '1px';
    v.style.transform = 'translateX(-0.5px)';
    v.style.display = 'block';
  }

  _hideMouseCrosshair() {
    if (this._mouseCrosshairHorizontalEl) {
      this._mouseCrosshairHorizontalEl.style.display = 'none';
    }
    if (this._mouseCrosshairVerticalEl) {
      this._mouseCrosshairVerticalEl.style.display = 'none';
    }
  }

  _mapAbsXToInternalX(absX, layout) {
    const drawScale = layout?.drawScale ?? 1;
    if (!Number.isFinite(absX)) return 0;
    return absX / Math.max(1e-6, drawScale);
  }

  _mapAbsYToLocalY(absY, plan, layout) {
    if (!Number.isFinite(absY)) return 0;
    const imgH = plan?.imageHeight ?? layout?.imageHeight ?? 1;
    const rowDrawH = plan?.rowDrawH ?? layout?.rowDrawH ?? 1;
    const yFirst = plan?.yFirst ?? 1;
    const rowIndex = Math.floor(absY / Math.max(1e-6, imgH)) + 1; // 1-based
    const yWithinOriginal = absY - (rowIndex - 1) * imgH;
    const yGlobalInternal =
      (rowIndex - 1) * rowDrawH + yWithinOriginal * (rowDrawH / Math.max(1e-6, imgH));
    return yGlobalInternal - yFirst * rowDrawH;
  }

  _drawVerticalLineOnOffscreen(offCtx, wPx, hPx, plan, layout, verticalLineCfg) {
    if (!verticalLineCfg || !verticalLineCfg.enabled) return;
    const start = verticalLineCfg.start || {};
    const end = verticalLineCfg.end || {};

    const startX = Number(start.x);
    const startY = Number(start.y);
    const endX = Number(end.x);
    const endY = Number(end.y);

    // y=-1 允许（异常值），由 clip 自动裁剪到可视范围
    if (!Number.isFinite(startX) || !Number.isFinite(endX) || !Number.isFinite(startY) || !Number.isFinite(endY)) return;

    const x0 = this._mapAbsXToInternalX(startX, layout);
    const x1 = this._mapAbsXToInternalX(endX, layout);
    const y0 = this._mapAbsYToLocalY(startY, plan, layout);
    const y1 = this._mapAbsYToLocalY(endY, plan, layout);


    const color = verticalLineCfg.color || 'red';
    const lineWidth = Number(verticalLineCfg.lineWidth ?? 1);

    offCtx.save();
    offCtx.beginPath();
    offCtx.rect(0, 0, wPx, hPx);
    offCtx.clip();
    offCtx.strokeStyle = color;
    offCtx.lineWidth = Math.max(1, lineWidth);
    offCtx.translate(0, -0.5);
    offCtx.beginPath();
    offCtx.moveTo(x0, y0);
    offCtx.lineTo(x1, y1);
    offCtx.stroke();
    offCtx.restore();
  }

  _getCellNaturalWidth(cell) {
    if (!cell) return 1;
    const colKey = cellColKey(cell);
    if (this.uniformColumnWidth) {
      return GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] || 1;
    }
    const key = cellWidthCacheKey(cell);
    return GLOBAL_CELL_WIDTH_BY_KEY[key] || GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] || 1;
  }

  /**
   * 统计列宽与全局行高（naturalWidth / naturalHeight）
   * - uniformColumnWidth=true：每 surface+imageX 采样一张，整列共用列宽
   * - uniformColumnWidth=false（默认）：每张图单独取宽并缓存，布局列宽为该列最大值
   * - 高度：仍只需首次成功取值（假定各行一致）
   */
  async _ensureGlobalMetrics(parsed, token) {
    const cells = Array.isArray(parsed) ? parsed.filter((c) => c && c.url) : [];
    const uniform = this.uniformColumnWidth;

    const CONCURRENCY = 6;
    let idx = 0;

    const applyNaturalSize = (width, height, colKey, cacheKey) => {
      if (uniform) {
        if (!(GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] > 0)) {
          GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] = width;
        }
      } else if (cacheKey) {
        if (!(GLOBAL_CELL_WIDTH_BY_KEY[cacheKey] > 0)) {
          GLOBAL_CELL_WIDTH_BY_KEY[cacheKey] = width;
        }
        const prevMax = GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] || 0;
        if (width > prevMax) {
          GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] = width;
        }
      }
      if (!GLOBAL_ROW_IMAGE_HEIGHT) {
        GLOBAL_ROW_IMAGE_HEIGHT = height;
      }
    };

    const loadOneUniform = async (colKey, sample) => {
      if (token !== this._renderToken) return;
      if (GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] > 0 && GLOBAL_ROW_IMAGE_HEIGHT > 0) {
        return;
      }
      if (!sample || !sample.url) return;
      try {
        const { width, height } = await loadImageNatural(sample.url);
        if (token !== this._renderToken) return;
        applyNaturalSize(width, height, colKey, null);
      } catch (e) {
        console.error('[DiskDirStrip] new Image 获取宽高失败 colKey=' + colKey, e);
        if (token !== this._renderToken) return;
        if (!(GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] > 0)) GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] = 800;
        if (!GLOBAL_ROW_IMAGE_HEIGHT) GLOBAL_ROW_IMAGE_HEIGHT = 200;
      }
    };

    const loadOnePerCell = async (cell) => {
      if (token !== this._renderToken) return;
      const cacheKey = cellWidthCacheKey(cell);
      if (GLOBAL_CELL_WIDTH_BY_KEY[cacheKey] > 0 && GLOBAL_ROW_IMAGE_HEIGHT > 0) {
        return;
      }
      const colKey = cellColKey(cell);
      try {
        const { width, height } = await loadImageNatural(cell.url);
        if (token !== this._renderToken) return;
        applyNaturalSize(width, height, colKey, cacheKey);
      } catch (e) {
        console.error(
          '[DiskDirStrip] new Image 获取宽高失败 surface=' +
            cell.surface +
            ' imageX=' +
            cell.imageX +
            ' imageY=' +
            cell.imageY,
          e
        );
        if (token !== this._renderToken) return;
        if (!(GLOBAL_CELL_WIDTH_BY_KEY[cacheKey] > 0)) {
          GLOBAL_CELL_WIDTH_BY_KEY[cacheKey] = 800;
        }
        const prevMax = GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] || 0;
        if (800 > prevMax) GLOBAL_COL_WIDTH_BY_IMAGE_X[colKey] = 800;
        if (!GLOBAL_ROW_IMAGE_HEIGHT) GLOBAL_ROW_IMAGE_HEIGHT = 200;
      }
    };

    const queue = uniform
      ? buildOrderedColumnKeys(cells).map((colKey) => {
          const sample = cells.find((c) => cellColKey(c) === colKey);
          return { colKey, sample };
        })
      : cells;

    const workers = new Array(Math.min(CONCURRENCY, Math.max(1, queue.length))).fill(0).map(async () => {
      while (idx < queue.length) {
        const item = queue[idx++];
        if (token !== this._renderToken) return;
        if (uniform) {
          await loadOneUniform(item.colKey, item.sample);
        } else {
          await loadOnePerCell(item);
        }
      }
    });
    await Promise.all(workers);
    return token === this._renderToken;
  }

  _buildLayout(parsed, token, viewBoxWidth, emendBaseLeftInfo) {
    const columnKeys = buildOrderedColumnKeys(parsed);
    const imageYs = [...new Set(parsed.map((c) => c.imageY))].sort((a, b) => a - b);
    const colMeta = Object.create(null);
    for (const cell of parsed) {
      const key = cellColKey(cell);
      if (!colMeta[key]) {
        colMeta[key] = { surface: cell.surface, imageX: cell.imageX };
      }
    }

    const colWidths = {};
    /** 同一 surface 内的列起始 X（不含 surface 条带起点） */
    const localXOffsets = {};
    const surfaceWidthAcc = Object.create(null);
    for (const key of columnKeys) {
      let w = GLOBAL_COL_WIDTH_BY_IMAGE_X[key] || 0;
      if (!this.uniformColumnWidth) {
        for (const cell of parsed) {
          if (cellColKey(cell) !== key) continue;
          const cellW = GLOBAL_CELL_WIDTH_BY_KEY[cellWidthCacheKey(cell)] || 0;
          if (cellW > w) w = cellW;
        }
      }
      colWidths[key] = w || 1;
      const surface = colMeta[key]?.surface ?? '';
      if (surfaceWidthAcc[surface] == null) surfaceWidthAcc[surface] = 0;
      localXOffsets[key] = surfaceWidthAcc[surface];
      surfaceWidthAcc[surface] += colWidths[key];
    }

    /** 各 surface 条带在画布上的起始 X（原始像素） */
    const surfaceBaseLeft = computeSurfaceBaseLeft(
      columnKeys,
      colWidths,
      colMeta,
      emendBaseLeftInfo
    );
    let totalWidth = 0;
    for (const surface of Object.keys(surfaceWidthAcc)) {
      const right = (surfaceBaseLeft[surface] || 0) + surfaceWidthAcc[surface];
      if (right > totalWidth) totalWidth = right;
    }

    const imageHeight = GLOBAL_ROW_IMAGE_HEIGHT || 1;
    // displayWidth：可视区宽（canvas_render_box.clientWidth）
    const displayWidth = Math.max(1, Math.floor(this.container.clientWidth || 0));
    const viewportH = Math.max(1, Math.floor(this.container.clientHeight || 0));

    // drawScale：画布内部绘制时的“缩小倍数”（整数）
    // 例：原始总宽 8000，可视区宽 1000，则 drawScale = floor(8000/1000)=8
    const drawScale = Math.max(1, Math.floor(totalWidth / Math.max(1, displayWidth)));

    // 最小画布宽：比可视区略大（通过 drawScale 整数化导致）
    const canvasWidth = Math.max(1, Math.ceil(totalWidth / drawScale));

    // CSS 缩放：把最小画布宽压到可视区宽
    const cssScale = displayWidth / canvasWidth;

    // 画布内实际绘制尺寸（按 drawScale 缩小）
    const canvasColW = {};
    /** surface 内列偏移（canvas 坐标） */
    const canvasXOff = {};
    /** surface 条带起点（canvas 坐标） */
    const canvasSurfaceBaseLeft = {};
    for (const key of columnKeys) {
      canvasXOff[key] = (localXOffsets[key] || 0) / drawScale;
      canvasColW[key] = (colWidths[key] || 1) / drawScale;
    }
    for (const surfaceKey of Object.keys(surfaceBaseLeft)) {
      canvasSurfaceBaseLeft[surfaceKey] = surfaceBaseLeft[surfaceKey] / drawScale;
    }
    // 每行绘制高度向下取整，避免纵向亚像素叠加产生撕裂
    const rowDrawH = Math.max(1, Math.floor(imageHeight / drawScale));

    // 一屏：可视区未缩放高度 / 每行整数高度
    const rowsPerScreen = Math.max(
      1,
      Math.ceil(viewportH / Math.max(0.0001, cssScale) / rowDrawH)
    );
    const numScreens = Math.ceil(imageYs.length / rowsPerScreen);

    const colWidthLog = {};
    columnKeys.forEach((key) => {
      colWidthLog[key] = colWidths[key];
    });
    console.log('[DiskDirStripCanvasRenderer]', {
      图片总数: parsed.length,
      列宽模式: this.uniformColumnWidth ? '同列等宽' : '同列可不等宽',
      列宽_原始像素: colWidthLog,
      surfaceBaseLeft,
      localXOffsets,
      图片高度_原始像素: imageHeight,
      原始总宽_totalWidth: totalWidth,
      displayWidth,
      drawScale,
      canvasWidth,
      cssScale,
      计划分屏数_numScreens: numScreens,
      rowsPerScreen,
      列序: columnKeys,
    });

    return {
      columnKeys,
      imageYs,
      colWidths,
      colMeta,
      surfaceBaseLeft,
      localXOffsets,
      imageHeight,
      totalWidth,
      displayWidth,
      drawScale,
      canvasWidth,
      cssScale,
      canvasColW,
      canvasXOff,
      canvasSurfaceBaseLeft,
      rowDrawH,
      rowsPerScreen,
      numScreens,
      viewportH,
    };
  }

  /**
   * 在已知 layout / 文件名解析结果后，即可算出每屏 canvas 尺寸与待绘单元格（无需等图片加载）。
   * 用于先批量挂 DOM，再逐屏只更新像素，减少「每 append 一次就长高」带来的多次布局。
   */
  _getScreenPlan(screenIndex, layout, parsed) {
    const { imageYs, rowsPerScreen, canvasWidth, canvasColW, canvasXOff, rowDrawH, colWidths, imageHeight } =
      layout;
    const rowStart = screenIndex * rowsPerScreen;
    const rowEnd = Math.min(rowStart + rowsPerScreen, imageYs.length);
    if (rowStart >= imageYs.length) return null;

    const screenImageYs = new Set(imageYs.slice(rowStart, rowEnd));
    const cells = parsed.filter((c) => screenImageYs.has(c.imageY));
    if (cells.length === 0) return null;

    const yFirst = imageYs[rowStart];
    const yLast = imageYs[rowEnd - 1];
    const screenCanvasHeight = Math.max(1, (yLast - yFirst + 1) * rowDrawH);
    const wPx = Math.max(1, Math.round(canvasWidth));
    const hPx = screenCanvasHeight;

    return {
      cells,
      yFirst,
      yLast,
      wPx,
      hPx,
      canvasColW,
      canvasXOff,
      rowDrawH,
      colWidths,
      imageHeight,
    };
  }

  _createMainCanvasElement(wPx, hPx) {
    const mainCanvas = document.createElement('canvas');
    mainCanvas.width = wPx;
    mainCanvas.height = hPx;
    mainCanvas.className = 'disk-strip-main-canvas';
    mainCanvas.style.display = 'block';
    mainCanvas.style.width = `${wPx}px`;
    mainCanvas.style.height = `${hPx}px`;
    mainCanvas.style.verticalAlign = 'top';
    return mainCanvas;
  }

  /**
   * 向已存在的 mainCanvas 绘制一屏内容（离屏合成后 blit），不在此操作 DOM。
   * @returns {boolean} 是否成功绘制并入屏
   */
  async _renderScreenToCanvas(screenIndex, layout, parsed, token, taskId, stripTiming, mainCanvas) {
    if (!this._isTaskValid(taskId)) return false;
    const plan = this._getScreenPlan(screenIndex, layout, parsed);
    if (!plan || !mainCanvas) return false;

    const {
      cells,
      yFirst,
      yLast,
      wPx,
      hPx,
      canvasColW,
      canvasXOff,
      rowDrawH,
      colWidths,
      imageHeight,
    } = plan;

    const lifecycle =
      stripTiming && typeof stripTiming === 'object'
        ? {
            onFetchStart: () => {
              if (token !== this._renderToken) return;
              if (stripTiming.firstFetchStart == null) {
                stripTiming.firstFetchStart = performance.now();
              }
            },
            onNetworkBytesReady: () => {
              if (stripTiming && token === this._renderToken) {
                stripTiming.lastNetworkEnd = performance.now();
              }
            },
          }
        : undefined;
    /** 整张图 loadBitmap Promise 落定（含 createImageBitmap 解码） */
    const markFetchEnd = () => {
      if (stripTiming && token === this._renderToken) {
        stripTiming.lastFetchEnd = performance.now();
      }
    };

    const offscreen =
      typeof OffscreenCanvas !== 'undefined' ? new OffscreenCanvas(wPx, hPx) : document.createElement('canvas');
    offscreen.width = wPx;
    offscreen.height = hPx;
    const offCtx = offscreen.getContext('2d');
    if (!offCtx) return false;

    const yOffset = (yFirst - 1) * rowDrawH;
    const canvasSurfaceBaseLeft = layout.canvasSurfaceBaseLeft || Object.create(null);
    const drawOne = (cell, source) => {
      if (cell.imageY < yFirst || cell.imageY > yLast) return;
      const dy = (cell.imageY - 1) * rowDrawH - yOffset;
      const colKey = cellColKey(cell);
      const dw = canvasColW[colKey] || 1;
      const dx = Math.round(
        (canvasSurfaceBaseLeft[cell.surface] || 0) + (canvasXOff[colKey] || 0)
      );
      const dh = rowDrawH;
      const cw = this._getCellNaturalWidth(cell);
      const ch = imageHeight;
      offCtx.drawImage(source, 0, 0, cw, ch, dx, dy, dw, dh);
    };

    const total = cells.length;
    let done = 0;
    const markDone = () => {
      done++;
    };

    await Promise.all(
      cells.map((cell) =>
        StripImageLoader.loadBitmap(cell.url, this.maxConcurrentFetch, lifecycle)
          .then((bitmap) => {
            if (token !== this._renderToken || !this._isTaskValid(taskId)) {
              if (bitmap) {
                try {
                  bitmap.close();
                } catch (_) {}
              }
              markFetchEnd();
              markDone();
              return;
            }
            if (bitmap) {
              drawOne(cell, bitmap);
              try {
                bitmap.close();
              } catch (_) {}
            }
            markFetchEnd();
            markDone();
          })
          .catch(() => {
            markFetchEnd();
            markDone();
          })
      )
    );
    if (token !== this._renderToken || !this._isTaskValid(taskId)) return false;
    if (done !== total) {
      console.warn('[DiskDirStrip] screen not fully done', { screenIndex, done, total });
    }

    const mainCtx = mainCanvas.getContext('2d');
    if (mainCtx && offscreen) {
      // 叠加竖线（head -> tail），按屏幕范围 clip
      try {
        this._drawVerticalLineOnOffscreen(offCtx, wPx, hPx, plan, layout, layout.__verticalLineConfig);
      } catch (e) {
        console.error('[DiskDirStrip] drawVerticalLine error', e);
      }
      mainCtx.drawImage(offscreen, 0, 0, wPx, hPx, 0, 0, wPx, hPx);
    }

    return true;
  }

  _getInnerEl() {
    if (this.inner && typeof this.inner.appendChild === 'function') {
      return this.inner;
    }
    if (this.container && this.container.querySelector) {
      return this.container.querySelector('.canvas_render_box_inner');
    }
    return null;
  }

  async render(params, hooks = {}) {
    if (this._destroyed) return;
    const token = ++this._renderToken;
    const taskId = this._beginNewTask();
    const {
      filesDataList,
      imagePrePath,
      viewBoxWidth: vbParam,
      verticalLine,
      uniformColumnWidth: uniformColumnWidthParam,
      emendBaseLeftInfo,
    } = params || {};
    if (uniformColumnWidthParam !== undefined) {
      this.uniformColumnWidth = uniformColumnWidthParam === true;
    }
    const names = Array.isArray(filesDataList) ? filesDataList : [];
    const onFirstScreen = hooks.onFirstScreen;
    const onComplete = hooks.onComplete;
    const onTiming = hooks.onTiming;

    /** 每次 render 重置宽高缓存，由 _ensureGlobalMetrics 重新 new Image 采集 */
    clearDiskStripGlobalColumnCache();

    this._clearDom();

    const sortedParsed = this._parseFilesToSortedCells(filesDataList, imagePrePath);
    if (!sortedParsed.length) {
      const innerEl = this._getInnerEl();
      if (innerEl) {
        innerEl.style.width = '100%';
        innerEl.style.transform = 'none';
      }
      this._hideVerticalLineTooltip();
      onComplete && onComplete();
      return;
    }

    /** 条带分屏耗时采集（不含 _ensureGlobalMetrics 的 new Image 列宽请求） */
    const stripTiming = {
      firstFetchStart: null,
      /** 最后一格 arrayBuffer 读完时刻（不含解码） */
      lastNetworkEnd: null,
      /** 最后一格 createImageBitmap 完成时刻（含解码） */
      lastFetchEnd: null,
      allPaintedAt: null,
      totalImages: null,
      canvasCount: null,
    };

    const vbw =
      vbParam != null && vbParam > 0
        ? vbParam
        : Math.max(1, this.container.clientWidth || this.container.getBoundingClientRect().width || 800);

    const ok = await this._ensureGlobalMetrics(sortedParsed, token);
    if (!ok || token !== this._renderToken || !this._isTaskValid(taskId)) {
      onComplete && onComplete();
      return;
    }

    const layout = this._buildLayout(sortedParsed, token, vbw, emendBaseLeftInfo);
    if (token !== this._renderToken || !this._isTaskValid(taskId)) {
      onComplete && onComplete();
      return;
    }

    const { numScreens } = layout;
    const innerEl = this._getInnerEl();
    if (innerEl) {
      this._applyInnerLayout(innerEl, layout);
    }

    // 给 _renderScreenToCanvas 使用的当前渲染周期 verticalLine 配置
    layout.__verticalLineConfig = verticalLine && verticalLine.enabled ? verticalLine : null;
    const verticalLineHoverEnabled = !!(verticalLine && verticalLine.enabled && verticalLine.hoverEnabled);
    const verticalLineStartX = verticalLine?.start ? Number(verticalLine.start.x) : NaN;
    const verticalLineStartY = verticalLine?.start ? Number(verticalLine.start.y) : NaN;

    const tooltipEl = verticalLineHoverEnabled ? this._ensureVerticalLineTooltip() : null;
    if (tooltipEl && this.container && this.container.style) {
      if (!this.container.style.position) this.container.style.position = 'relative';
    }

    // 先根据 layout 算出每屏尺寸，一次性创建并挂到 inner（DocumentFragment 单次挂载），
    // 再逐屏 fetch+绘制，避免每屏 append 导致容器高度多次增长、多次布局。
    const screenCanvases = [];
    if (innerEl) {
      const frag = document.createDocumentFragment();
      for (let s = 0; s < numScreens; s++) {
        const plan = this._getScreenPlan(s, layout, sortedParsed);
        if (!plan) continue;
        const canvas = this._createMainCanvasElement(plan.wPx, plan.hPx);
        // 鼠标 hover 显示：相对竖线起点（head）
        if (
          tooltipEl &&
          Number.isFinite(verticalLineStartX) &&
          Number.isFinite(verticalLineStartY) &&
          verticalLineStartY !== -1
        ) {
          const PX_TO_MMX = 0.2816;
          const PX_TO_MMY = 0.5632;
          const yFirst = plan.yFirst;
          const rowDrawH = layout.rowDrawH;
          const imageHeight = layout.imageHeight;
          const drawScale = layout.drawScale;
          const startX = verticalLineStartX;
          const startY = verticalLineStartY;
          const cssScaleVal = layout.cssScale || 1;

          let raf = 0;
          canvas.addEventListener(
            'mousemove',
            (ev) => {
              if (raf) return;
              raf = requestAnimationFrame(() => {
                raf = 0;
                const rect = canvas.getBoundingClientRect();
                const xCss = ev.clientX - rect.left;
                const yCss = ev.clientY - rect.top;
                if (xCss < 0 || yCss < 0 || xCss > rect.width || yCss > rect.height) {
                  this._hideMouseCrosshair();
                  return;
                }
                this._updateMouseCrosshair(canvas, ev);

                // 内部绘制坐标（去掉 cssScale）
                const xInternal = xCss / Math.max(1e-6, cssScaleVal);
                const yInternal = yCss / Math.max(1e-6, cssScaleVal);

                // x：内部坐标 * drawScale -> 原始像素坐标
                const xAbsOriginal = xInternal * drawScale;

                // y：内部坐标需要考虑 renderer 每行 rowDrawH 的 floor 映射误差
                const yGlobalInternal = (yFirst - 1) * rowDrawH + yInternal;
                const rowIndex = Math.floor(yGlobalInternal / Math.max(1e-6, rowDrawH)) + 1;
                const yWithinInternal = yGlobalInternal - (rowIndex - 1) * rowDrawH;
                const yWithinOriginal = yWithinInternal * (imageHeight / Math.max(1e-6, rowDrawH));
                const yAbsOriginal = rowIndex * imageHeight + yWithinOriginal;

                const dxMM = (xAbsOriginal - startX) * PX_TO_MMX;
                const dyMM = (yAbsOriginal - startY) * PX_TO_MMY;

                tooltipEl.innerHTML = `实际坐标(mm)：X ${dxMM.toFixed(2)} , Y ${dyMM.toFixed(2)}`;

                const cRect = this.container.getBoundingClientRect();
                const xInContainer = ev.clientX - cRect.left;
                const yInContainer = ev.clientY - cRect.top;
                const midX = cRect.width / 2;
                const midY = cRect.height / 2;
                const placeLeft = xInContainer < midX;
                const placeTop = yInContainer < midY;
                if (placeLeft) {
                  tooltipEl.style.left = `${xInContainer + 12}px`;
                  tooltipEl.style.right = 'auto';
                } else {
                  tooltipEl.style.left = 'auto';
                  tooltipEl.style.right = `${cRect.width - xInContainer + 12}px`;
                }
                if (placeTop) {
                  tooltipEl.style.top = `${yInContainer + 12}px`;
                  tooltipEl.style.bottom = 'auto';
                } else {
                  tooltipEl.style.top = 'auto';
                  tooltipEl.style.bottom = `${cRect.height - yInContainer + 12}px`;
                }
                tooltipEl.style.transformOrigin = `${placeTop ? 'top' : 'bottom'} ${placeLeft ? 'left' : 'right'}`;
                tooltipEl.style.display = 'block';
              });
            },
            { passive: true }
          );
          canvas.addEventListener('mouseleave', () => {
            this._hideVerticalLineTooltip();
            this._hideMouseCrosshair();
          });
        }

        screenCanvases.push({ screenIndex: s, canvas, plan });
        frag.appendChild(canvas);
      }
      innerEl.appendChild(frag);
    }

    stripTiming.totalImages = sortedParsed.length;
    stripTiming.canvasCount = screenCanvases.length;

    let firstDone = false;
    for (const { screenIndex, canvas } of screenCanvases) {
      if (token !== this._renderToken || !this._isTaskValid(taskId)) break;
      const painted = await this._renderScreenToCanvas(
        screenIndex,
        layout,
        sortedParsed,
        token,
        taskId,
        stripTiming,
        canvas
      );
      if (!firstDone && painted && onFirstScreen) {
        firstDone = true;
        try {
          onFirstScreen();
        } catch (_) {}
      }
    }

    // lastNetworkEnd：每张图 arrayBuffer 读完时更新；此处「总请求耗时」不含 createImageBitmap 解码（与 networkTotalMs 一致）
    if (
      token === this._renderToken &&
      this._isTaskValid(taskId) &&
      stripTiming.firstFetchStart != null &&
      stripTiming.lastNetworkEnd != null
    ) {
      const networkOnlyMs = stripTiming.lastNetworkEnd - stripTiming.firstFetchStart;
      const decodeWallMs =
        stripTiming.lastFetchEnd != null
          ? stripTiming.lastFetchEnd - stripTiming.firstFetchStart
          : null;
      console.log(
        '[DiskDirStripCanvasRenderer] 总请求耗时',
        `${networkOnlyMs.toFixed(2)} 毫秒 约 ${(networkOnlyMs / 1000).toFixed(2)} 秒`,
        `共 ${stripTiming.totalImages} 张图片，${stripTiming.canvasCount} 个 canvas`,
        '(firstFetchStart → lastNetworkEnd)'
      );
      // if (decodeWallMs != null) {
      //   console.log(
      //     '[DiskDirStripCanvasRenderer] 参考：含解码墙钟（至 lastFetchEnd）',
      //     `${decodeWallMs.toFixed(2)} 毫秒 约 ${(decodeWallMs / 1000).toFixed(2)} 秒`
      //   );
      // }
    }

    if (token === this._renderToken && this._isTaskValid(taskId) && stripTiming.firstFetchStart != null) {
      await new Promise((resolve) => {
        requestAnimationFrame(() => {
          requestAnimationFrame(() => resolve());
        });
      });
      stripTiming.allPaintedAt = performance.now();
      const totalRenderMs = stripTiming.allPaintedAt - stripTiming.firstFetchStart;
      console.log(
        '[DiskDirStripCanvasRenderer] 全部渲染完成耗时',
        `${totalRenderMs.toFixed(2)} 毫秒 约 ${(totalRenderMs / 1000).toFixed(2)} 秒`,
        `共 ${stripTiming.totalImages} 张图片，${stripTiming.canvasCount} 个 canvas`,
        '(firstFetchStart → allPaintedAt)'
      );
      const timingResult = buildStripTimingResult(stripTiming);
      if (timingResult) {
        console.log('[DiskDirStripCanvasRenderer] stripTiming', timingResult);
      }
      try {
        onTiming && onTiming(timingResult);
      } catch (_) {}
    }

    if (token === this._renderToken && this._isTaskValid(taskId)) {
      this._commitRenderState(
        filesDataList,
        imagePrePath,
        sortedParsed,
        layout,
        screenCanvases,
        emendBaseLeftInfo
      );
    }

    onComplete && onComplete();
  }

  /** 清空 DOM 与增量渲染缓存（换板、手动清画布时调用） */
  clearRenderCache() {
    this._clearDom();
  }

  _clearDom() {
    const innerEl = this._getInnerEl();
    if (innerEl) {
      while (innerEl.firstChild) {
        innerEl.removeChild(innerEl.firstChild);
      }
      innerEl.style.transform = 'none';
      innerEl.style.transformOrigin = '0 0';
    }
    this._lastRenderState = null;
    this._hideVerticalLineTooltip();
    this._hideMouseCrosshair();
    if (this._loupe) {
      this._loupe.setOpen(false);
    }
  }

  /**
   * 新列表是否在旧列表基础上仅尾部追加（路径字符串一致的前缀）
   * @param {string[]} prevFiles
   * @param {string[]} nextFiles
   */
  static canAppendIncremental(prevFiles, nextFiles) {
    const prev = Array.isArray(prevFiles) ? prevFiles : [];
    const next = Array.isArray(nextFiles) ? nextFiles : [];
    if (!prev.length || next.length <= prev.length) return false;
    for (let index = 0; index < prev.length; index++) {
      if (prev[index] !== next[index]) return false;
    }
    return true;
  }

  _parseFilesToSortedCells(filesDataList, imagePrePath) {
    const names = Array.isArray(filesDataList) ? filesDataList : [];
    const pre = imagePrePath != null && imagePrePath !== '' ? String(imagePrePath).replace(/\\/g, '/') : null;
    const parsed = [];
    for (const fileName of names) {
      const path = pre != null ? (pre.endsWith('/') ? pre + fileName : pre + '/' + fileName) : fileName;
      const parsedSuffix = parsePathSuffix(path);
      if (!parsedSuffix) continue;
      const url = this.buildImageUrl(path);
      parsed.push({ ...parsedSuffix, path, url });
    }
    return sortParsedCells(parsed);
  }

  _applyInnerLayout(innerEl, layout) {
    if (!innerEl || !layout) return;
    const { cssScale, canvasWidth } = layout;
    innerEl.style.display = 'block';
    innerEl.style.boxSizing = 'content-box';
    innerEl.style.transformOrigin = '0 0';
    innerEl.style.transform = `scale(${cssScale})`;
    innerEl.style.width = `${Math.max(1, Math.round(canvasWidth))}px`;
    innerEl.setAttribute('data-strip-scale', String(Math.round(cssScale * 10000) / 10000));
  }

  _syncScreenCanvasesFromDom(innerEl) {
    if (!innerEl) return [];
    const nodes = innerEl.querySelectorAll('canvas.disk-strip-main-canvas');
    const list = [];
    nodes.forEach((canvas, screenIndex) => {
      list.push({ screenIndex, canvas });
    });
    return list;
  }

  /**
   * 移除旧 canvas 并新建（重置位图与样式），用于增量时最后一屏完全重绘
   */
  _recreateScreenCanvasElement(innerEl, screenCanvases, screenIndex, plan) {
    const listIndex = screenCanvases.findIndex((item) => item.screenIndex === screenIndex);
    if (listIndex >= 0) {
      const oldCanvas = screenCanvases[listIndex].canvas;
      if (oldCanvas && oldCanvas.parentNode) {
        oldCanvas.parentNode.removeChild(oldCanvas);
      }
      screenCanvases.splice(listIndex, 1);
    }
    const canvas = this._createMainCanvasElement(plan.wPx, plan.hPx);
    if (innerEl) {
      innerEl.appendChild(canvas);
    }
    screenCanvases.push({ screenIndex, canvas });
    screenCanvases.sort((left, right) => left.screenIndex - right.screenIndex);
    return canvas;
  }

  _commitRenderState(filesDataList, imagePrePath, sortedParsed, layout, screenCanvases, emendBaseLeftInfo) {
    this._lastRenderState = {
      filesDataList: Array.isArray(filesDataList) ? filesDataList.slice() : [],
      imagePrePath: imagePrePath != null && imagePrePath !== '' ? String(imagePrePath) : '',
      sortedParsed,
      layout,
      screenCanvases: Array.isArray(screenCanvases) ? screenCanvases.slice() : [],
      emendBaseLeftInfo,
    };
  }

  /**
   * 从当前已渲染的最后一个 canvas 起增量更新（仅适用于新 files 列表在旧列表尾部追加）
   * @param {object} params 与 render 相同
   * @param {object} hooks 与 render 相同
   */
  async renderIncremental(params, hooks = {}) {
    if (this._destroyed) return;
    const prevState = this._lastRenderState;
    const names = Array.isArray(params?.filesDataList) ? params.filesDataList : [];
    if (
      !prevState ||
      !prevState.filesDataList?.length ||
      !DiskDirStripCanvasRenderer.canAppendIncremental(prevState.filesDataList, names)
    ) {
      return this.render(params, hooks);
    }

    const token = ++this._renderToken;
    const taskId = this._beginNewTask();
    const {
      filesDataList,
      imagePrePath,
      viewBoxWidth: vbParam,
      verticalLine,
      uniformColumnWidth: uniformColumnWidthParam,
      emendBaseLeftInfo,
    } = params || {};
    if (uniformColumnWidthParam !== undefined) {
      this.uniformColumnWidth = uniformColumnWidthParam === true;
    }
    const onFirstScreen = hooks.onFirstScreen;
    const onComplete = hooks.onComplete;
    const onTiming = hooks.onTiming;

    const sortedParsed = this._parseFilesToSortedCells(filesDataList, imagePrePath);
    if (!sortedParsed.length) {
      this._clearDom();
      onComplete && onComplete();
      return;
    }

    const stripTiming = {
      firstFetchStart: null,
      lastNetworkEnd: null,
      lastFetchEnd: null,
      allPaintedAt: null,
      totalImages: null,
      canvasCount: null,
    };

    const vbw =
      vbParam != null && vbParam > 0
        ? vbParam
        : Math.max(1, this.container.clientWidth || this.container.getBoundingClientRect().width || 800);

    const ok = await this._ensureGlobalMetrics(sortedParsed, token);
    if (!ok || token !== this._renderToken || !this._isTaskValid(taskId)) {
      onComplete && onComplete();
      return;
    }

    const layout = this._buildLayout(sortedParsed, token, vbw, emendBaseLeftInfo);
    if (token !== this._renderToken || !this._isTaskValid(taskId)) {
      onComplete && onComplete();
      return;
    }

    layout.__verticalLineConfig = verticalLine && verticalLine.enabled ? verticalLine : null;

    const innerEl = this._getInnerEl();
    if (!innerEl) {
      onComplete && onComplete();
      return;
    }

    this._applyInnerLayout(innerEl, layout);

    let screenCanvases = this._syncScreenCanvasesFromDom(innerEl);
    if (!screenCanvases.length) {
      return this.render(params, hooks);
    }

    const startScreenIndex = Math.max(0, screenCanvases.length - 1);
    const { numScreens } = layout;

    if (numScreens < screenCanvases.length) {
      while (screenCanvases.length > numScreens) {
        const removed = screenCanvases.pop();
        if (removed?.canvas?.parentNode) {
          removed.canvas.parentNode.removeChild(removed.canvas);
        }
      }
    }

    for (let screenIndex = startScreenIndex; screenIndex < numScreens; screenIndex++) {
      if (token !== this._renderToken || !this._isTaskValid(taskId)) break;
      const plan = this._getScreenPlan(screenIndex, layout, sortedParsed);
      if (!plan) continue;

      let canvas = null;
      const isIncrementalLastScreen = screenIndex === startScreenIndex;
      if (isIncrementalLastScreen) {
        // 增量起点：最后一屏 DOM 与位图均重建，再按当前 layout 绘制该屏全部单元格
        canvas = this._recreateScreenCanvasElement(innerEl, screenCanvases, screenIndex, plan);
      } else {
        canvas = this._createMainCanvasElement(plan.wPx, plan.hPx);
        innerEl.appendChild(canvas);
        screenCanvases.push({ screenIndex, canvas });
      }

      const painted = await this._renderScreenToCanvas(
        screenIndex,
        layout,
        sortedParsed,
        token,
        taskId,
        stripTiming,
        canvas
      );
      if (screenIndex === startScreenIndex && painted && onFirstScreen) {
        try {
          onFirstScreen();
        } catch (_) {}
      }
    }

    screenCanvases = this._syncScreenCanvasesFromDom(innerEl);
    stripTiming.totalImages = sortedParsed.length;
    stripTiming.canvasCount = screenCanvases.length;

    if (token === this._renderToken && this._isTaskValid(taskId) && stripTiming.firstFetchStart != null) {
      await new Promise((resolve) => {
        requestAnimationFrame(() => {
          requestAnimationFrame(() => resolve());
        });
      });
      stripTiming.allPaintedAt = performance.now();
      const timingResult = buildStripTimingResult(stripTiming);
      try {
        onTiming && onTiming(timingResult);
      } catch (_) {}
    }

    if (token === this._renderToken && this._isTaskValid(taskId)) {
      this._commitRenderState(filesDataList, imagePrePath, sortedParsed, layout, screenCanvases, emendBaseLeftInfo);
    }

    onComplete && onComplete();
  }

  destroy() {
    this._destroyed = true;
    this._renderToken++;
    DiskDirStripCanvasRenderer.invalidateGlobalTask();
    this._currentTaskId = null;
    if (this._loupe) {
      this._loupe.detach();
      this._loupe = null;
    }
    this._clearDom();
  }
}

export { parsePathSuffix };
