<template>
  <div class="tile-panel tile-img-panel">
    <!-- <el-alert
      type="info"
      :closable="false"
      show-icon
      class="img-tip"
      title="模拟原生IMG加载渲染"
    /> -->

    <el-card shadow="never" class="perf-card" v-loading="summaryLoading">
      <div slot="header" class="perf-header">IMG 性能指标</div>
      <el-row :gutter="12">
        <el-col :span="8">
          <div class="perf-item">
            <div class="perf-label">首图可见</div>
            <div class="perf-value">{{ formatMs(perfSummary?.firstVisibleMs) }}</div>
          </div>
        </el-col>
        <el-col :span="8">
          <div class="perf-item">
            <div class="perf-label">全部加载完成</div>
            <div class="perf-value">{{ formatMs(perfSummary?.allLoadedMs) }}</div>
          </div>
        </el-col>
        <el-col :span="8">
          <div class="perf-item">
            <div class="perf-label">已加载</div>
            <div class="perf-value">{{ handledCount }} / {{ totalCount }}</div>
          </div>
        </el-col>
      </el-row>
    </el-card>

    <div class="tile-viewport img-scroll-wrap">
      <div :key="renderKey" class="img_strip_scroll_box">
        <div
          v-for="row in rows"
          :key="'row-' + row.imageY"
          class="img_strip_row"
        >
          <template v-for="cell in row.cells">
            <img
              v-if="srcMap[cell.virtualName]"
              :key="cell.virtualName"
              class="img_strip_cell"
              :src="srcMap[cell.virtualName]"
              :alt="cell.virtualName"
              :data-virtual-name="cell.virtualName"
              decoding="async"
              @load="onImgLoad(cell)"
              @error="onImgError(cell)"
            >
            <div
              v-else
              :key="'ph-' + cell.virtualName"
              class="img_strip_placeholder"
            >
              <span v-if="loadingCells.includes(cell.virtualName)" class="ph-loading">加载中</span>
            </div>
          </template>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import {
  getMapImageCount,
  getSortedMapCells,
  groupCellsByRow,
  buildMapImageUrl
} from '@/utils/mapImageAssets.js'

function randomNetworkDelay () {
  return 80 + Math.floor(Math.random() * 200)
}

/** 每批随机 1 或 2 张 */
function randomBatchSize () {
  return Math.random() < 0.5 ? 1 : 2
}

function shuffleList (list) {
  const arr = list.slice()
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    const tmp = arr[i]
    arr[i] = arr[j]
    arr[j] = tmp
  }
  return arr
}

function sleep (ms) {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

export default {
  name: 'TileImgPanel',
  data () {
    return {
      rows: [],
      flatCells: [],
      srcMap: {},
      renderKey: 0,
      loadingCells: [],
      handledCount: 0,
      errorCount: 0,
      perfSummary: null,
      loadSession: 0,
      loadToken: 0,
      loadStart: 0,
      firstVisibleAt: null,
      /** virtualName -> { resolve, reject, session } */
      pendingLoads: Object.create(null)
    }
  },
  computed: {
    totalCount () {
      return getMapImageCount()
    },
    summaryLoading () {
      return !this.perfSummary
    }
  },
  beforeDestroy () {
    this.stopLoader()
  },
  methods: {
    formatMs (ms) {
      if (ms == null || !Number.isFinite(ms)) return '-'
      return `${ms.toFixed(2)} ms（${(ms / 1000).toFixed(2)} s）`
    },

    stopLoader () {
      this.loadSession += 1
      Object.keys(this.pendingLoads).forEach((key) => {
        const pending = this.pendingLoads[key]
        if (pending && typeof pending.reject === 'function') {
          pending.reject(new Error('cancelled'))
        }
      })
      this.pendingLoads = Object.create(null)
    },

    resetLoadState () {
      this.srcMap = {}
      this.loadingCells = []
      this.handledCount = 0
      this.errorCount = 0
      this.perfSummary = null
      this.loadStart = 0
      this.firstVisibleAt = null
    },

    reload () {
      this.stopLoader()
      this.resetLoadState()

      const session = this.loadSession
      this.renderKey += 1
      this.loadToken = Date.now()

      const cells = getSortedMapCells()
      this.flatCells = cells
      this.rows = groupCellsByRow(cells)
      if (!cells.length) return

      this.loadStart = performance.now()
      this.runRandomBatchLoad(session)
    },

    async runRandomBatchLoad (session) {
      const queue = shuffleList(
        this.flatCells.map((cell, seq) => ({ cell, seq }))
      )
      let cursor = 0

      while (cursor < queue.length) {
        if (session !== this.loadSession) return

        await sleep(randomNetworkDelay())
        if (session !== this.loadSession) return

        const batchSize = Math.min(randomBatchSize(), queue.length - cursor)
        const batch = queue.slice(cursor, cursor + batchSize)
        cursor += batchSize

        this.loadingCells = batch.map((item) => item.cell.virtualName)

        try {
          const results = await Promise.all(
            batch.map(({ cell, seq }) =>
              this.loadOneImage(
                cell,
                buildMapImageUrl(cell.virtualName, `${this.loadToken}_${seq}`),
                session
              ).catch((e) => {
                if (e && e.message === 'cancelled') throw e
                return true
              })
            )
          )

          if (session !== this.loadSession) return

          results.forEach((isError) => {
            const now = performance.now()
            if (this.firstVisibleAt == null && !isError) {
              this.firstVisibleAt = now
            }
            if (isError) this.errorCount += 1
            this.handledCount += 1
          })
        } catch (e) {
          if (e && e.message === 'cancelled') return
        }

        this.loadingCells = []
      }

      if (session !== this.loadSession) return
      this.finishPerf()
    },

    loadOneImage (cell, url, session) {
      return new Promise((resolve, reject) => {
        if (session !== this.loadSession) {
          reject(new Error('cancelled'))
          return
        }

        this.pendingLoads[cell.virtualName] = { resolve, reject, session }

        this.$set(this.srcMap, cell.virtualName, url)

        this.$nextTick(() => {
          if (session !== this.loadSession) {
            this.clearPending(cell.virtualName)
            reject(new Error('cancelled'))
            return
          }

          const img = this.$el.querySelector(
            `img.img_strip_cell[data-virtual-name="${cell.virtualName}"]`
          )
          if (img && img.complete) {
            const ok = img.naturalWidth > 0
            this.clearPending(cell.virtualName)
            resolve(!ok)
          }
        })
      })
    },

    clearPending (virtualName) {
      delete this.pendingLoads[virtualName]
    },

    onImgLoad (cell) {
      const pending = this.pendingLoads[cell.virtualName]
      if (!pending) return
      this.clearPending(cell.virtualName)
      pending.resolve(false)
    },

    onImgError (cell) {
      console.error('[TileImgPanel] load failed', cell.virtualName)
      const pending = this.pendingLoads[cell.virtualName]
      if (!pending) return
      this.clearPending(cell.virtualName)
      pending.resolve(true)
    },

    finishPerf (endAt) {
      if (this.perfSummary) return
      const end = endAt != null ? endAt : performance.now()
      this.perfSummary = {
        firstVisibleMs: this.firstVisibleAt != null ? this.firstVisibleAt - this.loadStart : null,
        allLoadedMs: end - this.loadStart
      }
      console.log('[TileImgPanel] perf', this.perfSummary)
    }
  }
}
</script>

<style scoped>
.tile-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
}

.img-tip {
  margin-bottom: 12px;
}

.tile-viewport {
  flex: 1;
  min-height: 360px;
  border: 1px solid #dcdfe6;
  border-radius: 4px;
}

.img-scroll-wrap {
  overflow-y: scroll;
  overflow-x: hidden;
  background: #1a1a1a;
}

.img_strip_scroll_box {
  width: 100%;
}

.img_strip_row {
  display: flex;
  flex-direction: row;
  flex-wrap: nowrap;
  width: 100%;
  line-height: 0;
}

.img_strip_cell,
.img_strip_placeholder {
  display: block;
  width: 20%;
  flex: 0 0 20%;
  height: auto;
  box-sizing: border-box;
}

.img_strip_placeholder {
  min-height: 48px;
  background: #2a2a2a;
  border: 1px solid #3a3a3a;
  display: flex;
  align-items: center;
  justify-content: center;
}

.ph-loading {
  color: #909399;
  font-size: 12px;
  line-height: 1.4;
}

.perf-card {
  margin-bottom: 12px;
}

.perf-card >>> .el-card__header {
  padding: 10px 16px;
}

.perf-card >>> .el-card__body {
  padding: 12px 16px;
}

.perf-header {
  font-weight: 600;
}

.perf-item {
  text-align: center;
  padding: 10px;
  background: #f5f7fa;
  border-radius: 4px;
}

.perf-label {
  color: #909399;
  font-size: 13px;
  margin-bottom: 6px;
}

.perf-value {
  color: #303133;
  font-size: 15px;
  font-weight: 600;
}
</style>
