<template>
  <div class="tile-mosaic-page">
    <div class="page-header">
      <div class="page-title-wrap">
        <h2 class="page-title">分块拼屏</h2>
        <span class="page-desc">无数小图拼接浏览大图 · 共 {{ fileCount }} 张</span>
      </div>
      <el-button size="small" type="primary" icon="el-icon-refresh" @click="reloadActive">
        重新加载
      </el-button>
    </div>

    <el-tabs v-model="activeTab" class="tile-tabs">
      <el-tab-pane label="原生 IMG" name="img">
        <tile-img-panel ref="imgPanel" />
      </el-tab-pane>
      <el-tab-pane label="Canvas 方案" name="canvas" lazy>
        <tile-canvas-panel ref="canvasPanel" />
      </el-tab-pane>
    </el-tabs>
  </div>
</template>

<script>
import TileImgPanel from '@/components/TileImgPanel.vue'
import TileCanvasPanel from '@/components/TileCanvasPanel.vue'
import { getMapImageCount } from '@/utils/mapImageAssets.js'

export default {
  name: 'TileMosaic',
  components: {
    TileImgPanel,
    TileCanvasPanel
  },
  data () {
    return {
      activeTab: 'img'
    }
  },
  computed: {
    fileCount () {
      return getMapImageCount()
    }
  },
  mounted () {
    this.$nextTick(() => {
      this.$refs.imgPanel && this.$refs.imgPanel.reload()
    })
  },
  methods: {
    reloadActive () {
      if (this.activeTab === 'img' && this.$refs.imgPanel) {
        this.$refs.imgPanel.reload()
      } else if (this.activeTab === 'canvas' && this.$refs.canvasPanel) {
        this.$refs.canvasPanel.reload()
      }
    }
  }
}
</script>

<style scoped>
.tile-mosaic-page {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 520px;
}

.page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 12px;
  padding: 0 4px;
}

.page-title-wrap {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.page-title {
  margin: 0;
  font-size: 20px;
  color: #303133;
}

.page-desc {
  font-size: 13px;
  color: #909399;
}

.tile-tabs {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.tile-tabs >>> .el-tabs__content {
  flex: 1;
  min-height: 0;
}

.tile-tabs >>> .el-tab-pane {
  height: 100%;
}
</style>
